import React from 'react';
import './Dashboard.css';

const Dashboard = () => {
  const stats = [
    { title: 'Total users', value: '24,589', change: '+12%', icon: 'fa-users' },
    { title: 'Total content', value: '1,808', change: '+5%', icon: 'fa-book' },
    { title: 'Online now', value: '1,245', change: '+3%', icon: 'fa-eye' },
    { title: 'New today', value: '89', change: '+8%', icon: 'fa-user-plus' }
  ];

  return (
    <div className="admin-dashboard">
      <h1>Admin Dashboard</h1>
      <p>Manage users, content, chapters, videos and settings from one place.</p>

      <div className="stats-grid">
        {stats.map((item) => (
          <div key={item.title} className="stat-card">
            <div className="stat-header">
              <span className="stat-title">{item.title}</span>
              <div className="stat-icon"><i className={`fas ${item.icon}`}></i></div>
            </div>
            <div className="stat-value">{item.value}</div>
            <div className="stat-change positive">{item.change} this week</div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Dashboard;
